     new Dictionary<long, Func<long, string>>
     {
         { 1_000_000_000, n => $"{Convert(n)} billion" },
         { 1_000_000, n => $"{Convert(n)} million" },
         { 1_000, n => $"{Convert(n)} thousand" },
     }.ToFrozenDictionary();

 public string Convert(long number)
 {
